// src/pages/CreateCourse.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { coursesService } from '../services/courses';
import axios from 'axios';
import api from '../services/api';

// ─── helpers ─────────────────────────────────────────────────────────────────

const emptySection = () => ({
  id: Date.now(),          // local key only
  title: '',
  description: '',
  order: 0,
  lectures: [],
});

const emptyLecture = (sectionLocalId) => ({
  id: Date.now() + Math.random(),
  sectionLocalId,
  title: '',
  description: '',
  video_type: 'upload',   // 'upload' | 'youtube' | 'vimeo'
  video_url: '',
  file: null,             // File object when video_type === 'upload'
  s3_key: '',
  duration_minutes: 0,
  order: 0,
  is_free_preview: false,
  uploadProgress: 0,
  uploadStatus: '',       // '' | 'uploading' | 'done' | 'error'
});

// ─── component ────────────────────────────────────────────────────────────────

const CreateCourse = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  // ── ALL hooks must be before any early return ────────────────────────────
  const [courseData, setCourseData] = useState({
    title: '',
    description: '',
    price: '',
    image: null,
  });
  const [sections, setSections] = useState([emptySection()]);
  const [submitting, setSubmitting] = useState(false);

  // Early return AFTER hooks
  if (!user || !user.is_instructor) {
    alert('فقط المدرّسين يمكنهم إنشاء كورسات');
    navigate('/');
    return null;
  }

  // ── Course field handlers ─────────────────────────────────────────────────
  const handleCourseChange = (e) => {
    const { name, value, files } = e.target;
    setCourseData((prev) => ({
      ...prev,
      [name]: files ? files[0] : value,
    }));
  };

  // ── Section handlers ──────────────────────────────────────────────────────
  const addSection = () =>
    setSections((prev) => [
      ...prev,
      { ...emptySection(), order: prev.length },
    ]);

  const removeSection = (sId) =>
    setSections((prev) => prev.filter((s) => s.id !== sId));

  const updateSection = (sId, field, value) =>
    setSections((prev) =>
      prev.map((s) => (s.id === sId ? { ...s, [field]: value } : s))
    );

  // ── Lecture handlers ──────────────────────────────────────────────────────
  const addLecture = (sId) =>
    setSections((prev) =>
      prev.map((s) =>
        s.id === sId
          ? {
              ...s,
              lectures: [
                ...s.lectures,
                { ...emptyLecture(sId), order: s.lectures.length },
              ],
            }
          : s
      )
    );

  const removeLecture = (sId, lId) =>
    setSections((prev) =>
      prev.map((s) =>
        s.id === sId
          ? { ...s, lectures: s.lectures.filter((l) => l.id !== lId) }
          : s
      )
    );

  const updateLecture = (sId, lId, field, value) =>
    setSections((prev) =>
      prev.map((s) =>
        s.id === sId
          ? {
              ...s,
              lectures: s.lectures.map((l) =>
                l.id === lId ? { ...l, [field]: value } : l
              ),
            }
          : s
      )
    );

  // ── S3 direct upload ──────────────────────────────────────────────────────
  const uploadVideoToS3 = async (sId, lId, file) => {
    updateLecture(sId, lId, 'uploadStatus', 'uploading');
    updateLecture(sId, lId, 'uploadProgress', 0);

    try {
      // 1. Get presigned URL from backend
      const { data } = await api.post('/courses/lectures/presigned-upload/', {
        file_name: file.name,
        file_type: file.type,
      });

      const { upload_url, s3_key } = data;

      // 2. PUT directly to S3 (no auth header – S3 handles it via the presigned URL)
      await axios.put(upload_url, file, {
        headers: { 'Content-Type': file.type },
        onUploadProgress: (e) => {
          const pct = Math.round((e.loaded / e.total) * 100);
          updateLecture(sId, lId, 'uploadProgress', pct);
        },
      });

      // 3. Save s3_key in local state so we can submit it later
      updateLecture(sId, lId, 's3_key', s3_key);
      updateLecture(sId, lId, 'uploadStatus', 'done');
    } catch (err) {
      console.error('S3 upload failed', err);
      updateLecture(sId, lId, 'uploadStatus', 'error');
    }
  };

  // ── Form submit ───────────────────────────────────────────────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      // 1. Create the course
      const fd = new FormData();
      fd.append('title', courseData.title);
      fd.append('description', courseData.description);
      fd.append('price', courseData.price);
      if (courseData.image) fd.append('image', courseData.image);

      const courseRes = await coursesService.create(fd);
      const courseId = courseRes.id;

      // 2. Create sections & lectures sequentially
      for (let si = 0; si < sections.length; si++) {
        const sec = sections[si];

        const secRes = await api.post('/courses/sections/', {
          course: courseId,
          title: sec.title,
          description: sec.description,
          order: si,
        });
        const sectionId = secRes.data.id;

        for (let li = 0; li < sec.lectures.length; li++) {
          const lec = sec.lectures[li];

          // Validate: upload type must have s3_key
          if (lec.video_type === 'upload' && !lec.s3_key) {
            alert(`الليكتشر "${lec.title}" لسه ما اترفعش على S3`);
            setSubmitting(false);
            return;
          }

          await api.post('/courses/lectures/', {
            section: sectionId,
            title: lec.title,
            description: lec.description,
            video_type: lec.video_type,
            video_url: lec.video_type !== 'upload' ? lec.video_url : '',
            s3_key: lec.video_type === 'upload' ? lec.s3_key : '',
            duration_minutes: lec.duration_minutes,
            order: li,
            is_free_preview: lec.is_free_preview,
          });
        }
      }

      alert('تم إنشاء الكورس بنجاح! في انتظار موافقة الأدمن.');
      navigate('/courses');
    } catch (err) {
      console.error(err.response?.data || err);
      alert('فشل إنشاء الكورس: ' + (err.response?.data?.detail || 'حدث خطأ'));
    } finally {
      setSubmitting(false);
    }
  };

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div style={s.page}>
      <div style={s.card}>
        <h2 style={s.heading}>إنشاء كورس جديد</h2>

        <form onSubmit={handleSubmit}>
          {/* ── Course basics ── */}
          <section style={s.section}>
            <h3 style={s.subHeading}>معلومات الكورس</h3>

            <label style={s.label}>العنوان</label>
            <input style={s.input} name="title" value={courseData.title}
              onChange={handleCourseChange} required />

            <label style={s.label}>الوصف</label>
            <textarea style={{ ...s.input, height: 100 }} name="description"
              value={courseData.description} onChange={handleCourseChange} required />

            <label style={s.label}>السعر (EGP)</label>
            <input style={s.input} type="number" name="price" value={courseData.price}
              onChange={handleCourseChange} min="0" step="0.01" required />

            <label style={s.label}>صورة الغلاف</label>
            <input type="file" name="image" accept="image/*" onChange={handleCourseChange} />
          </section>

          {/* ── Sections ── */}
          <section style={s.section}>
            <div style={s.row}>
              <h3 style={s.subHeading}>الأقسام (Sections)</h3>
              <button type="button" style={s.btnBlue} onClick={addSection}>+ قسم جديد</button>
            </div>

            {sections.map((sec, si) => (
              <div key={sec.id} style={s.sectionBox}>
                {/* Section header */}
                <div style={s.row}>
                  <strong>القسم {si + 1}</strong>
                  <button type="button" style={s.btnRed}
                    onClick={() => removeSection(sec.id)}>حذف القسم</button>
                </div>

                <label style={s.label}>عنوان القسم</label>
                <input style={s.input} value={sec.title}
                  onChange={(e) => updateSection(sec.id, 'title', e.target.value)} required />

                <label style={s.label}>وصف القسم (اختياري)</label>
                <input style={s.input} value={sec.description}
                  onChange={(e) => updateSection(sec.id, 'description', e.target.value)} />

                {/* ── Lectures ── */}
                {sec.lectures.map((lec, li) => (
                  <div key={lec.id} style={s.lectureBox}>
                    <div style={s.row}>
                      <strong>ليكتشر {li + 1}</strong>
                      <button type="button" style={s.btnRed}
                        onClick={() => removeLecture(sec.id, lec.id)}>حذف</button>
                    </div>

                    <label style={s.label}>عنوان الليكتشر</label>
                    <input style={s.input} value={lec.title}
                      onChange={(e) => updateLecture(sec.id, lec.id, 'title', e.target.value)} required />

                    <label style={s.label}>نوع الفيديو</label>
                    <select style={s.input} value={lec.video_type}
                      onChange={(e) => updateLecture(sec.id, lec.id, 'video_type', e.target.value)}>
                      <option value="upload">رفع فيديو على S3</option>
                      <option value="youtube">رابط YouTube</option>
                      <option value="vimeo">رابط Vimeo</option>
                    </select>

                    {lec.video_type === 'upload' ? (
                      <div>
                        <label style={s.label}>اختر الفيديو</label>
                        <input type="file" accept="video/*"
                          onChange={(e) => {
                            const file = e.target.files[0];
                            updateLecture(sec.id, lec.id, 'file', file);
                          }} />
                        {lec.file && lec.uploadStatus !== 'done' && (
                          <button type="button" style={{ ...s.btnBlue, marginTop: 6 }}
                            onClick={() => uploadVideoToS3(sec.id, lec.id, lec.file)}>
                            ⬆ ارفع الفيديو على S3
                          </button>
                        )}
                        {lec.uploadStatus === 'uploading' && (
                          <div style={s.progressWrap}>
                            <div style={{ ...s.progressBar, width: `${lec.uploadProgress}%` }} />
                            <span style={s.progressLabel}>{lec.uploadProgress}%</span>
                          </div>
                        )}
                        {lec.uploadStatus === 'done' && <p style={s.success}>✅ تم الرفع – في انتظار موافقة الأدمن</p>}
                        {lec.uploadStatus === 'error' && <p style={s.error}>❌ فشل الرفع، حاول تاني</p>}
                      </div>
                    ) : (
                      <div>
                        <label style={s.label}>الرابط</label>
                        <input style={s.input} type="url" placeholder="https://..."
                          value={lec.video_url}
                          onChange={(e) => updateLecture(sec.id, lec.id, 'video_url', e.target.value)} />
                      </div>
                    )}

                    <div style={s.row}>
                      <div>
                        <label style={s.label}>المدة (دقيقة)</label>
                        <input style={{ ...s.input, width: 100 }} type="number" min="0"
                          value={lec.duration_minutes}
                          onChange={(e) => updateLecture(sec.id, lec.id, 'duration_minutes', +e.target.value)} />
                      </div>
                      <label style={{ marginTop: 28, cursor: 'pointer' }}>
                        <input type="checkbox" checked={lec.is_free_preview}
                          onChange={(e) => updateLecture(sec.id, lec.id, 'is_free_preview', e.target.checked)} />
                        {' '}معاينة مجانية
                      </label>
                    </div>
                  </div>
                ))}

                <button type="button" style={{ ...s.btnBlue, marginTop: 8 }}
                  onClick={() => addLecture(sec.id)}>+ ليكتشر جديد</button>
              </div>
            ))}
          </section>

          <button type="submit" style={s.btnSubmit} disabled={submitting}>
            {submitting ? 'جاري الإنشاء...' : 'إنشاء الكورس'}
          </button>
        </form>
      </div>
    </div>
  );
};

// ── Styles ────────────────────────────────────────────────────────────────────
const s = {
  page: { background: '#f4f6f8', minHeight: '100vh', padding: '40px 20px' },
  card: { background: '#fff', borderRadius: 12, padding: 30, maxWidth: 750, margin: '0 auto',
          boxShadow: '0 10px 25px rgba(0,0,0,0.08)' },
  heading: { marginBottom: 20, color: '#1a1a2e' },
  subHeading: { color: '#333', margin: '0 0 12px' },
  section: { marginBottom: 30, paddingBottom: 20, borderBottom: '1px solid #eee' },
  sectionBox: { background: '#f9f9f9', border: '1px solid #e0e0e0', borderRadius: 8,
                padding: 16, marginBottom: 16 },
  lectureBox: { background: '#fff', border: '1px solid #ddd', borderRadius: 6,
                padding: 12, marginTop: 12 },
  label: { display: 'block', fontWeight: 500, marginBottom: 4, marginTop: 10, fontSize: 14 },
  input: { width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid #ccc',
           fontSize: 14, boxSizing: 'border-box' },
  row: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 },
  btnBlue: { background: '#007bff', color: '#fff', border: 'none', borderRadius: 6,
             padding: '7px 14px', cursor: 'pointer', fontSize: 13 },
  btnRed: { background: '#dc3545', color: '#fff', border: 'none', borderRadius: 6,
            padding: '5px 12px', cursor: 'pointer', fontSize: 13 },
  btnSubmit: { background: '#28a745', color: '#fff', border: 'none', borderRadius: 8,
               padding: '12px 28px', fontSize: 16, cursor: 'pointer', marginTop: 10 },
  progressWrap: { position: 'relative', background: '#e9ecef', borderRadius: 6,
                  height: 20, marginTop: 8, overflow: 'hidden' },
  progressBar: { background: '#007bff', height: '100%', transition: 'width 0.3s' },
  progressLabel: { position: 'absolute', right: 8, top: 2, fontSize: 12, color: '#333' },
  success: { color: '#28a745', marginTop: 6, fontSize: 13 },
  error:   { color: '#dc3545', marginTop: 6, fontSize: 13 },
  uploadBox:   { background: '#f0f7ff', border: '1px dashed #90c2ff', borderRadius: 8, padding: 14, marginTop: 8 },
  fileInput:   { width: '100%', padding: '6px 0', fontSize: 14, cursor: 'pointer' },
  fileInfo:    { display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                 background: '#fff', borderRadius: 6, padding: '6px 10px', marginTop: 8,
                 border: '1px solid #ddd', fontSize: 13 },
  btnUpload:   { background: '#0066cc', color: '#fff', border: 'none', borderRadius: 6,
                 padding: '9px 18px', cursor: 'pointer', fontSize: 14, marginTop: 10, width: '100%', fontWeight: 600 },
  btnSmallGray:{ background: '#6c757d', color: '#fff', border: 'none', borderRadius: 6,
                 padding: '5px 12px', cursor: 'pointer', fontSize: 12, marginLeft: 10 },
  uploadDone:  { display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                 background: '#d4edda', borderRadius: 6, padding: '8px 12px', marginTop: 8,
                 color: '#155724', fontWeight: 500, fontSize: 13 },
};

export default CreateCourse;
